import React from "react"
import User from "./User"

class Users extends React.Component {
    users = this.props.state
    render() {
        return (
            <div>
                {this.state.users.map((item) => (
                    <User key={item.id} user={item}/>
                ))}
            </div>
        )
    }
}



export default Users
